  def _combine(objs: list[str]) -> str:
              """Combine a list of objects into a readable string."""
              if len(objs) == 1:
                  return objs[0]
              if len(objs) == 2:
                  return f"{objs[0]} and {objs[1]}"
              return ", ".join(objs[:-1]) + f", and {objs[-1]}"

          for pred, objs in pred_objs.items():
              generator = phrase_map.get(pred)
              if generator:
                  # Special handling for predicates where the verb phrase should be shared
                  if pred == "leader" and len(objs) > 1:
                      phrase = "is led by " + _combine(objs)
                  elif pred == "language" and len(objs) > 1:
                      langs = [o.replace(" language", "") for o in objs]
                      phrase = "speaks " + _combine(langs)
                  elif pred == "demonym" and len(objs) > 1:
                      phrase = "people are called " + _combine(objs)
                  else:
                      if len(objs) == 1:
                          phrase = generator(objs[0])
                      else:
                          # combine objects first, then generate a single phrase
                          combined_obj = _combine(objs)
                          phrase = generator(combined_obj)
              else:
                  phrase = f"{pred} {' and '.join(objs)}"
